/**
 * Version selector — runs in the browser on every generated docs page.
 *
 * Fetches versions.json from the namespace base URL, renders a <select>
 * dropdown, and navigates to the same relative path in the selected version.
 *
 * versions.json is generated by CI after each docs deploy and lives at:
 *   https://contentful.github.io/contentful-management.js/contentful-management/versions.json
 *
 * The script is injected inline by the typedoc-version-selector.mjs plugin so
 * it does not need to be registered as a separate file.
 */

;(function () {
  'use strict'

  var REPO_ROOT = 'https://contentful.github.io/contentful-management.js/'
  var NAMESPACE = 'contentful-management'
  var VERSIONS_URL = REPO_ROOT + NAMESPACE + '/versions.json'

  /**
   * Extract the semver-like version segment from the current URL path.
   * Matches patterns such as:
   *   /contentful-management.js/contentful-management/12.3.0/...
   *   /contentful-management.js/contentful-management/13.0.0-beta.1/...
   */
  function getCurrentVersion() {
    var match = window.location.pathname.match(
      /\/contentful-management\/([\d]+\.[\d]+\.[\d]+(?:-[\w.]+)?)\//,
    )
    return match ? match[1] : null
  }

  /**
   * Extract the path segment that comes after the version — this is the
   * "page within the docs" and is preserved when switching versions so the
   * user stays on the same page (if it exists in the new version).
   */
  function getRelativePath() {
    var match = window.location.pathname.match(
      /\/contentful-management\/[\d]+\.[\d]+\.[\d]+(?:-[\w.]+)?\/(.*)/,
    )
    return match ? match[1] : ''
  }

  function buildSelector(versions, currentVersion) {
    var container = document.createElement('div')
    container.id = 'version-selector-container'
    container.setAttribute('aria-label', 'Documentation version selector')

    var label = document.createElement('label')
    label.htmlFor = 'version-selector'
    label.textContent = 'Version'
    container.appendChild(label)

    var select = document.createElement('select')
    select.id = 'version-selector'
    select.setAttribute('aria-label', 'Select documentation version')

    // Newest first.
    versions.sort(function (a, b) {
      return b.localeCompare(a, undefined, { numeric: true, sensitivity: 'base' })
    })

    versions.forEach(function (v) {
      var option = document.createElement('option')
      option.value = v
      option.textContent = v === versions[0] ? v + ' (latest)' : v
      if (v === currentVersion) option.selected = true
      select.appendChild(option)
    })

    select.addEventListener('change', function () {
      var newVersion = encodeURIComponent(select.value)
      var relativePath = getRelativePath()
        .split('/')
        .map(encodeURIComponent)
        .join('/')
      var url = new URL(REPO_ROOT + NAMESPACE + '/' + newVersion + '/' + relativePath)
      if (url.origin === new URL(REPO_ROOT).origin) {
        window.location.href = url.href
      }
    })

    container.appendChild(select)
    return container
  }

  function insertSelector(selector) {
    // Try the TypeDoc / typedoc-github-theme toolbar first, then fall back to
    // the first <header> element, and finally prepend to <body>.
    var anchor =
      document.querySelector('.tsd-page-toolbar .tsd-toolbar-contents') ||
      document.querySelector('.tsd-page-toolbar') ||
      document.querySelector('header') ||
      document.body

    if (anchor === document.body) {
      anchor.insertBefore(selector, anchor.firstChild)
    } else {
      anchor.appendChild(selector)
    }
  }

  function init() {
    var currentVersion = getCurrentVersion()
    // Only activate on versioned pages (not on a plain local `file://` open).
    if (!currentVersion) return

    fetch(VERSIONS_URL)
      .then(function (res) {
        if (!res.ok) throw new Error('HTTP ' + res.status)
        return res.json()
      })
      .then(function (versions) {
        if (!Array.isArray(versions) || versions.length === 0) return
        var selector = buildSelector(versions, currentVersion)
        insertSelector(selector)
      })
      .catch(function (err) {
        // Non-fatal — silently skip if versions.json isn't available yet.
        if (typeof console !== 'undefined') {
          console.debug('[version-selector] Could not load versions.json:', err.message)
        }
      })
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init)
  } else {
    init()
  }
})()
